import React from "react";
import PropTypes from "prop-types";
import "./iphonePreviewStyles.css";

const phone = "data:image/png;base64,";
const notch = "data:image/png;base64,";

function IphonePreview({ content, overlayStyle }) {
    return (
        <div className="iphone-container">
            <img src={phone} alt="Illustration of an iPhone" style={{ width: "100%", display: "block" }} />
            <img src={notch} alt="iPhone Notch" className="iphone-notch" />
            <div className="iphone-overlay" style={overlayStyle}>{content}</div>
        </div>
    );
}

IphonePreview.propTypes = {
    content: PropTypes.node,
    overlayStyle: PropTypes.object,
};

IphonePreview.defaultProps = {
    content: null,
    overlayStyle: {},
};

export default React.memo(IphonePreview);